/// <summary>
/// Extension of the InventDim data source for the InventBatchIdLookup form, for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataSourceStr(InventBatchIdLookup, InventDim))]
final class InventBatchIdLookup_InventDimETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Obtains the operation name.
/// </summary>
/// <param name="_inventDim">
/// Record <c>InventDim</c>.
/// </param>
/// <returns>
/// Returns the operation name.
/// </returns>
[SysClientCacheDataMethodAttribute(true)]
display Name ETGSPAINdisplayOperationName(InventDim _inventDim)
{
    Name operationName = '';

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes && _inventDim.inventBatchId)
    {
        ETGSPAINPurchOperationTable purchOperationTable = ETGSPAINPurchOperationTable::find(_inventDim.inventBatchId);

        if (purchOperationTable)
        {
            operationName = purchOperationTable.Name;
        }
    }

    return operationName;
}

/// <summary>
/// Obtains the operation status.
/// </summary>
/// <param name="_inventDim">
/// Record <c>InventDim</c>.
/// </param>
/// <returns>
/// Returns the operation status.
/// </returns>
[SysClientCacheDataMethodAttribute(true)]
display ETGSPAINOperationStatus ETGSPAINdisplayOperationStatus(InventDim _inventDim)
{
    ETGSPAINOperationStatus operationStatus;

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes && _inventDim.inventBatchId)
    {
        ETGSPAINPurchOperationTable purchOperationTable = ETGSPAINPurchOperationTable::find(_inventDim.inventBatchId);

        if (purchOperationTable)
        {
            operationStatus = purchOperationTable.OperationStatus;
        }
    }

    return operationStatus;
}
